// AUTO-GENERATED from demo.html — do not edit by hand.
export const DEMO_HTML = "<!DOCTYPE html>\n<html lang=\"ko\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>셀러랩스 | 상품명 추천기 (독립 데모)</title>\n<link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/gh/orioncactus/pretendard@v1.3.9/dist/web/static/pretendard.css\">\n<style>\n  :root{\n    --bg:#FDF6F0; --card:#FFF; --ink:#2A2420; --gray:#8A817A; --line:#EFE6DC; --soft:#FFFBF7;\n    --primary:#FF6B4A; --primary-dark:#E5512F; --green:#1FA37A; --yellow:#E8A33D; --red:#E5604D;\n    --radius:20px; --shadow:0 12px 44px rgba(120,80,50,.10);\n    font-family:'Pretendard','Apple SD Gothic Neo',sans-serif;\n  }\n  *{margin:0;padding:0;box-sizing:border-box}\n  body{background:var(--bg);color:var(--ink);line-height:1.6;-webkit-font-smoothing:antialiased}\n  .wrap{max-width:1080px;margin:0 auto;padding:0 24px}\n  .btn{display:inline-block;background:var(--primary);color:#fff;border:none;padding:16px 28px;\n    border-radius:999px;font-size:16px;font-weight:700;cursor:pointer;transition:.2s;white-space:nowrap;\n    box-shadow:0 8px 22px rgba(255,107,74,.34);text-decoration:none}\n  .btn:hover{background:var(--primary-dark);transform:translateY(-2px)}\n  .btn:disabled{opacity:.6;cursor:default;transform:none}\n  .pill{display:inline-block;background:#FFF0EB;color:var(--primary-dark);padding:5px 14px;\n    border-radius:999px;font-size:13px;font-weight:600;margin:3px}\n  .pill-green{display:inline-block;background:#E9F7F1;color:#147A57;padding:5px 14px;\n    border-radius:999px;font-size:13px;font-weight:600;margin:3px}\n  .badge{display:inline-block;padding:3px 10px;border-radius:999px;font-size:12px;font-weight:700;margin-left:6px;vertical-align:middle}\n  .badge-live{background:#E9F7F1;color:#147A57}\n  .badge-demo{background:#FFF0EB;color:var(--primary-dark)}\n  .loading{display:flex;align-items:center;justify-content:center;gap:10px;padding:30px;color:var(--gray);font-weight:600}\n  .spinner{width:18px;height:18px;border:2.5px solid var(--line);border-top-color:var(--primary);border-radius:50%;animation:spin .7s linear infinite}\n  @keyframes spin{to{transform:rotate(360deg)}}\n  .err-box{padding:16px 18px;background:#FDECEA;border:1px solid #F5C6C0;border-radius:12px;color:#B03A2E;font-size:14px;font-weight:600;margin-top:20px}\n\n  nav{position:sticky;top:0;z-index:50;background:var(--bg);border-bottom:1px solid var(--line)}\n  nav .wrap{display:flex;align-items:center;justify-content:space-between;height:72px}\n  .logo{font-weight:800;font-size:21px;letter-spacing:-.5px}.logo span{color:var(--primary)}\n  nav .btn{padding:10px 22px;font-size:14px}\n\n  .hero{padding:72px 0 48px;text-align:center}\n  .hero .eyebrow{color:var(--primary);font-weight:700;font-size:15px;margin-bottom:14px}\n  .hero h1{font-size:clamp(28px,5vw,48px);font-weight:800;letter-spacing:-1.5px;line-height:1.28}\n  .hero h1 .hl{background:linear-gradient(transparent 58%,#FFD9A0 58%);padding:0 4px}\n  .hero p.lead{font-size:18px;color:var(--gray);margin:22px auto 0;max-width:600px}\n\n  .tool{margin:40px auto 0;max-width:760px;background:var(--card);border-radius:24px;box-shadow:var(--shadow);padding:32px;text-align:left}\n  .modes{display:flex;gap:8px;margin-bottom:22px;flex-wrap:wrap}\n  .mode-btn{flex:1;min-width:118px;padding:12px;border:1.5px solid var(--line);background:#fff;\n    border-radius:12px;font-weight:700;font-size:14px;cursor:pointer;color:var(--gray);transition:.2s}\n  .mode-btn.active{border-color:var(--primary);color:var(--primary);background:#FFF6F3}\n  label{display:block;font-weight:700;font-size:14px;margin-bottom:8px}\n  .input-row{display:flex;gap:10px}\n  .input-row input{flex:1;padding:16px 18px;border:1.5px solid var(--line);border-radius:12px;\n    font-size:16px;outline:none;transition:.2s;background:var(--soft)}\n  .input-row input:focus{border-color:var(--primary);background:#fff}\n  .extra{margin-top:14px;display:none;grid-template-columns:1fr 1fr;gap:10px}\n  .extra.show{display:grid}\n  .extra input{padding:13px 16px;border:1.5px solid var(--line);border-radius:10px;font-size:14px;outline:none;background:var(--soft)}\n  .current-box{margin-top:14px;display:none}.current-box.show{display:block}\n  .current-box input{width:100%;padding:13px 16px;border:1.5px dashed var(--line);border-radius:10px;font-size:14px;outline:none;background:var(--soft)}\n\n  .result{margin-top:26px;display:none;animation:fade .45s ease}.result.show{display:block}\n  @keyframes fade{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:none}}\n\n  .vs{display:grid;grid-template-columns:1fr auto 1fr;gap:14px;align-items:stretch;margin-bottom:20px}\n  .vs-col{border-radius:16px;padding:18px}\n  .vs-old{background:#F7F2EC;border:1px solid var(--line)}\n  .vs-new{background:linear-gradient(135deg,#FFF1EC,#FFF9F6);border:1.5px solid var(--primary)}\n  .vs-col .tag{font-size:12px;font-weight:700;margin-bottom:8px}\n  .vs-old .tag{color:var(--gray)}.vs-new .tag{color:var(--primary-dark)}\n  .vs-col .txt{font-size:17px;font-weight:800;letter-spacing:-.4px;line-height:1.4}\n  .vs-old .txt{color:#9A8F84}\n  .vs-arrow{display:flex;align-items:center;font-size:24px;color:var(--primary)}\n  .vs-delta{font-size:12px;margin-top:10px;font-weight:700}.vs-up{color:var(--green)}\n  .copy-btn{margin-top:12px;background:var(--primary);color:#fff;border:none;padding:8px 16px;border-radius:9px;font-weight:700;font-size:13px;cursor:pointer}\n  .copy-btn:hover{background:var(--primary-dark)}\n\n  .track-btn{width:100%;margin:18px 0;padding:16px;border:none;border-radius:14px;background:var(--primary);\n    color:#fff;font-size:16px;font-weight:700;cursor:pointer;transition:.2s;display:flex;flex-direction:column;\n    align-items:center;gap:4px;box-shadow:0 8px 22px rgba(255,107,74,.30)}\n  .track-btn:hover:not(:disabled){background:var(--primary-dark);transform:translateY(-2px)}\n  .track-btn:disabled{cursor:default}\n  .track-btn.done{background:var(--green);box-shadow:none}\n  .track-hint{font-size:11px;font-weight:500;opacity:.8}\n\n  .gauge-box{background:#fff;border:1px solid var(--line);border-radius:16px;padding:22px;margin-bottom:18px}\n  .gauge-head{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:10px}\n  .verdict{font-size:18px;font-weight:800}.gauge-score{font-size:13px;color:var(--gray)}\n  .gauge-track{height:12px;border-radius:99px;position:relative;background:linear-gradient(90deg,#1FA37A,#E8A33D,#E5604D)}\n  .gauge-needle{position:absolute;top:-5px;width:4px;height:22px;background:var(--ink);border-radius:2px;transform:translateX(-50%);transition:left .8s cubic-bezier(.2,.8,.2,1)}\n  .gauge-labels{display:flex;justify-content:space-between;font-size:11px;color:var(--gray);margin-top:8px}\n  .gauge-desc{font-size:13.5px;color:#5C534B;margin-top:14px;padding:12px 14px;background:var(--soft);border-radius:10px}\n  .opp-kw{margin-top:14px}.opp-label{font-size:12px;color:var(--gray);font-weight:700;margin-right:4px}\n\n  .meta-grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}\n  .meta-box{background:#fff;border:1px solid var(--line);border-radius:14px;padding:18px}\n  .meta-h4{font-size:13px;color:var(--gray);margin-bottom:12px;font-weight:700}\n  .kw-bar{margin-bottom:10px}\n  .kw-top{display:flex;justify-content:space-between;font-size:13px;margin-bottom:4px}\n  .kw-track{height:7px;background:var(--line);border-radius:99px;overflow:hidden}\n  .kw-fill{height:100%;background:linear-gradient(90deg,var(--primary),#FF9E85);border-radius:99px}\n  .total-vol{font-size:13px;color:var(--gray);margin-top:8px}.total-vol b{color:var(--primary);font-size:18px}\n  .reason{background:#fff;border:1px solid var(--line);border-radius:14px;padding:18px;margin-top:16px}\n  .reason ol{padding-left:18px;font-size:13.5px;color:#4A4240}.reason li{margin-bottom:5px}\n\n  .tracked-panel{margin-top:20px;padding:20px;background:var(--soft);border:1px solid var(--line);border-radius:16px}\n  .tracked-row{display:flex;justify-content:space-between;align-items:center;padding:14px;background:#fff;border:1px solid var(--line);border-radius:12px;margin-top:10px}\n  .tracked-name{font-weight:700;font-size:15px;letter-spacing:-.3px}\n  .tracked-meta{font-size:12px;color:var(--gray);margin-top:4px}\n  .tracked-del{background:none;border:1px solid var(--line);color:var(--gray);padding:6px 14px;border-radius:8px;font-size:13px;cursor:pointer;white-space:nowrap}\n  .tracked-del:hover{border-color:var(--red);color:var(--red)}\n\n  @media(max-width:760px){.meta-grid,.vs{grid-template-columns:1fr}.vs-arrow{transform:rotate(90deg);justify-content:center}}\n</style>\n</head>\n<body>\n\n<nav><div class=\"wrap\">\n  <div class=\"logo\">셀러<span>랩스</span></div>\n  <a href=\"#tool\" class=\"btn\">무료로 시작하기</a>\n</div></nav>\n\n<header class=\"hero\"><div class=\"wrap\">\n  <div class=\"eyebrow\">⚡ 셀러랩스 상품명 추천기 <span id=\"modeBadge\"></span></div>\n  <h1>키워드만 넣으면 <span class=\"hl\">상위노출 상품명</span>이 3초면 끝</h1>\n  <p class=\"lead\">네이버 쇼핑 상위 40개를 분석해, 검색에 가장 잘 걸리는 상품명을 자동으로 만들어 드려요.</p>\n\n  <div class=\"tool\" id=\"tool\">\n    <div class=\"modes\">\n      <button class=\"mode-btn active\" data-mode=\"quick\">⚡ 빠른 추천</button>\n      <button class=\"mode-btn\" data-mode=\"complete\">🎯 완벽 최적화</button>\n      <button class=\"mode-btn\" data-mode=\"competition\">📊 경쟁률 분석</button>\n    </div>\n\n    <label>상품 메인 키워드</label>\n    <div class=\"input-row\">\n      <input id=\"kwInput\" type=\"text\" placeholder=\"예) 새우 ✗ / 신안 새우 ✓\" value=\"대저토마토\">\n      <button class=\"btn\" id=\"genBtn\">상품명 생성</button>\n    </div>\n\n    <div class=\"extra\" id=\"extra\">\n      <input id=\"brand\" placeholder=\"브랜드 (선택)\">\n      <input id=\"volume\" placeholder=\"용량/수량 (선택, 예: 500g)\">\n    </div>\n    <div class=\"current-box\" id=\"currentBox\">\n      <label style=\"margin-top:14px\">현재 쓰고 있는 상품명 (비교용, 선택)</label>\n      <input id=\"currentName\" placeholder=\"예) 토마토 방울토마토 맛있는 토마토 판매\">\n    </div>\n\n    <div class=\"result\" id=\"result\"></div>\n    <div id=\"trackedListBox\"></div>\n  </div>\n</div></header>\n\n<script>\n/* ===================== 데모 데이터 ===================== */\nconst DEMO_DB = {\n  \"대저토마토\":{\n    category:\"식품 > 농산물 > 과일 > 토마토\",\n    keywords:[\n      {word:\"부산\",freq:12,volume:14800},{word:\"방울토마토\",freq:5,volume:18100},\n      {word:\"고당도\",freq:6,volume:8100},{word:\"제철\",freq:4,volume:9900},\n      {word:\"짭짤이\",freq:11,volume:3200},{word:\"완숙\",freq:8,volume:2900},\n      {word:\"대추\",freq:5,volume:5400},{word:\"찰\",freq:5,volume:1600},\n    ],\n    competition:{bundleRatio:0.0,avgReview:1.2,totalProducts:40,searchVolume:4680},\n    extraTags:[\"스테비아토마토\",\"못난이토마토\",\"흑토마토\",\"산지직송\",\"유럽종완숙\"],\n    oppKeywords:[\"흑대추방울토마토\",\"부산대저\",\"짭짜리\"]\n  },\n  \"신안새우\":{\n    category:\"식품 > 수산물 > 새우\",\n    keywords:[\n      {word:\"대하\",freq:10,volume:22000},{word:\"생새우\",freq:7,volume:9800},\n      {word:\"냉동\",freq:9,volume:6400},{word:\"손질\",freq:6,volume:4100},\n      {word:\"흰다리새우\",freq:5,volume:12000},{word:\"자연산\",freq:4,volume:3300},\n      {word:\"국내산\",freq:8,volume:7700},{word:\"왕새우\",freq:3,volume:5600},\n    ],\n    competition:{bundleRatio:0.45,avgReview:120,totalProducts:40,searchVolume:8200},\n    extraTags:[\"새우구이\",\"대하소금구이\",\"새우장\",\"급속냉동\",\"산지직송\"],\n    oppKeywords:[\"신안대하\",\"손질새우\",\"자연산대하\"]\n  }\n};\n\n/* ===================== 추천 엔진 ===================== */\nconst normalize=a=>{if(!a.length)return[];const lo=Math.min(...a),hi=Math.max(...a);return hi===lo?a.map(()=>1):a.map(v=>(v-lo)/(hi-lo));};\nfunction scoreKeywords(k){const nf=normalize(k.map(x=>x.freq)),nv=normalize(k.map(x=>x.volume));return k.map((x,i)=>({...x,score:nf[i]*0.6+nv[i]*0.4})).sort((a,b)=>b.score-a.score);}\nfunction buildName(main,kws,ex={},maxW=7,maxL=50){\n  const r=scoreKeywords(kws),out=[],used=new Set();\n  if(ex.brand){out.push(ex.brand);used.add(ex.brand);}\n  main.split(\" \").forEach(t=>{if(t&&!used.has(t)){out.push(t);used.add(t);}});\n  for(const k of r){if(out.length>=maxW)break;if(used.has(k.word))continue;\n    if([...used].some(u=>u.includes(k.word)||k.word.includes(u)))continue;\n    if([...out,k.word].join(\" \").length>maxL)continue;out.push(k.word);used.add(k.word);}\n  if(ex.volume&&[...out,ex.volume].join(\" \").length<=maxL)out.push(ex.volume);\n  return out.join(\" \");\n}\nfunction calcDifficulty(c){\n  const reviewN=Math.min(c.avgReview/50,1);\n  const comp=(c.bundleRatio*0.4)+(reviewN*0.4)+0.2;\n  const raw=comp*100*(1-Math.min(c.searchVolume/20000,0.6));\n  return Math.round(Math.min(Math.max(raw,5),95));\n}\nfunction verdictOf(s){\n  if(s<35)return{label:\"지금 들어가세요! 🟢\",color:\"var(--green)\",desc:\"상위노출 경쟁이 낮은 키워드예요. 상품명 최적화만 잘해도 광고 없이 순위가 올라갑니다.\"};\n  if(s<65)return{label:\"해볼 만해요 🟡\",color:\"var(--yellow)\",desc:\"경쟁이 보통 수준이에요. 상품명 + 리뷰 관리를 병행하면 충분히 상위권 진입이 가능합니다.\"};\n  return{label:\"경쟁이 셉니다 🔴\",color:\"var(--red)\",desc:\"이미 강한 셀러들이 자리잡은 키워드예요. 아래 기회 키워드로 우회하는 걸 추천드려요.\"};\n}\n\n/* ===================== 추적 저장소 (로컬 목업) ===================== */\nconst STORE_KEY=\"sl_tracked_products\";\nfunction getTracked(){try{return JSON.parse(localStorage.getItem(STORE_KEY)||\"[]\");}catch{return[];}}\nfunction isTracked(name){return getTracked().some(i=>i.productName===name);}\nasync function registerTracking(item){\n  // TODO: 셀러랩스 순위추적 API 연결\n  await new Promise(r=>setTimeout(r,600));\n  const saved={...item,id:\"local_\"+Date.now(),createdAt:new Date().toISOString()};\n  const list=getTracked();list.unshift(saved);\n  localStorage.setItem(STORE_KEY,JSON.stringify(list));\n  return saved;\n}\nfunction removeTracking(id){localStorage.setItem(STORE_KEY,JSON.stringify(getTracked().filter(i=>i.id!==id)));}\n\n/* ===================== 실데이터 모드 ===================== */\nlet LIVE=false; // 서버에 네이버 키가 있으면 true\nasync function detectMode(){\n  try{\n    const r=await fetch('/api/status');\n    if(r.ok){const j=await r.json();LIVE=!!j.liveData;}\n  }catch{LIVE=false;}\n  const badge=document.getElementById('modeBadge');\n  if(badge){\n    badge.className='badge '+(LIVE?'badge-live':'badge-demo');\n    badge.textContent=LIVE?'🟢 실데이터 (네이버 쇼핑)':'🟡 데모 데이터';\n  }\n}\n\n/* 더미 DEMO_DB → 공통 렌더 데이터 형태로 변환 */\nfunction fromDemo(kw){\n  const db=DEMO_DB[kw.replace(/\\s/g,'')]||DEMO_DB[kw]||DEMO_DB[\"대저토마토\"];\n  return {\n    keywords:db.keywords.map(k=>({word:k.word,freq:k.freq,volume:k.volume})),\n    category:db.category,\n    difficulty:calcDifficulty(db.competition),\n    extraTags:db.extraTags,\n    oppKeywords:db.oppKeywords,\n    hasVolume:true,\n    live:false\n  };\n}\n\n/* 실서버 /api/analyze → 공통 렌더 데이터 형태로 변환 */\nasync function fromApi(kw,ex){\n  const q=new URLSearchParams({kw});\n  if(ex.brand)q.set('brand',ex.brand);\n  if(ex.volume)q.set('volume',ex.volume);\n  const r=await fetch('/api/analyze?'+q.toString());\n  const j=await r.json();\n  if(!r.ok)throw new Error(j.detail||j.error||('HTTP '+r.status));\n  return {\n    keywords:j.keywords.map(k=>({word:k.word,freq:k.freq,volume:0})), // 검색량 API 미연동 → 빈도 기반\n    category:j.category||'(카테고리 정보 없음)',\n    difficulty:j.difficulty,\n    extraTags:j.tags||[],\n    oppKeywords:[],\n    sampleTitles:j.sampleTitles||[],\n    totalProducts:j.totalProducts,\n    serverName:j.recommendedName,\n    hasVolume:false,\n    live:true\n  };\n}\n\n/* ===================== UI 제어 ===================== */\nlet mode=\"quick\";\ndocument.querySelectorAll('.mode-btn').forEach(b=>b.onclick=()=>{\n  mode=b.dataset.mode;\n  document.querySelectorAll('.mode-btn').forEach(x=>x.classList.remove('active'));\n  b.classList.add('active');\n  document.getElementById('extra').classList.toggle('show',mode==='complete');\n  document.getElementById('currentBox').classList.toggle('show',mode==='complete');\n});\ndocument.getElementById('genBtn').onclick=generate;\ndocument.getElementById('kwInput').addEventListener('keydown',e=>{if(e.key==='Enter')generate();});\n\nasync function generate(){\n  const kw=document.getElementById('kwInput').value.trim();\n  if(!kw)return;\n  const ex={brand:document.getElementById('brand').value.trim(),volume:document.getElementById('volume').value.trim()};\n  const res=document.getElementById('result');\n  const genBtn=document.getElementById('genBtn');\n\n  // 데이터 획득 (실데이터 우선, 실패 시 더미 fallback)\n  let data;\n  if(LIVE){\n    res.classList.add('show');\n    res.innerHTML='<div class=\"loading\"><span class=\"spinner\"></span>네이버 쇼핑 상위 40개 분석 중…</div>';\n    genBtn.disabled=true;\n    try{\n      data=await fromApi(kw,ex);\n    }catch(e){\n      // 실패하면 데모로 폴백하되 안내\n      data=fromDemo(kw);\n      data._fallbackMsg='실데이터 조회 실패('+e.message+') → 데모 데이터로 표시합니다.';\n    }\n    genBtn.disabled=false;\n  }else{\n    data=fromDemo(kw);\n  }\n\n  render(kw,ex,data);\n}\n\nfunction render(kw,ex,db){\n  const name=db.serverName||buildName(kw,JSON.parse(JSON.stringify(db.keywords)),ex);\n  const used=name.split(\" \");\n  const bars=db.keywords.filter(k=>used.includes(k.word));\n  const maxV=Math.max(...bars.map(b=>b.volume||b.freq),1);\n  const total=db.hasVolume?bars.reduce((s,b)=>s+(b.volume||0),0):0;\n  const diff=db.difficulty;\n  const v=verdictOf(diff);\n  const cur=document.getElementById('currentName').value.trim();\n  let html=\"\";\n  if(db._fallbackMsg)html+=`<div class=\"err-box\">⚠️ ${esc(db._fallbackMsg)}</div>`;\n\n  if(mode==='complete'&&cur){\n    const curUsed=cur.split(/\\s+/);\n    const curMatch=db.keywords.filter(k=>curUsed.includes(k.word)).length;\n    const deltaTxt=db.hasVolume\n      ? `▲ ${(total-Math.round(total*0.35)).toLocaleString()}회 상승 (${total.toLocaleString()}회)`\n      : `▲ 상위노출 키워드 ${bars.length}개 반영 (현재 ${curMatch}개)`;\n    const oldTxt=db.hasVolume\n      ? `추정 노출 검색량 ${Math.round(total*0.35).toLocaleString()}회`\n      : `상위노출 키워드 ${curMatch}개 포함`;\n    html+=`<div class=\"vs\">\n      <div class=\"vs-col vs-old\"><div class=\"tag\">현재 상품명</div><div class=\"txt\">${esc(cur)}</div>\n        <div class=\"vs-delta\">${oldTxt}</div></div>\n      <div class=\"vs-arrow\">→</div>\n      <div class=\"vs-col vs-new\"><div class=\"tag\">추천 상품명</div><div class=\"txt\">${esc(name)}</div>\n        <div class=\"vs-delta vs-up\">${deltaTxt}</div>\n        <button class=\"copy-btn\" data-copy=\"${esc(name)}\">복사하기</button></div></div>`;\n  }else{\n    html+=`<div class=\"vs-col vs-new\" style=\"margin-bottom:20px\"><div class=\"tag\">추천 상품명</div>\n      <div class=\"txt\">${esc(name)}</div>\n      <button class=\"copy-btn\" data-copy=\"${esc(name)}\">복사하기</button></div>`;\n  }\n\n  const already=isTracked(name);\n  html+=`<button class=\"track-btn ${already?'done':''}\" id=\"trackBtn\" ${already?'disabled':''}>\n    <span id=\"trackLabel\">${already?'✓ 이미 추적 중':'📌 이 상품명으로 순위추적 등록하기'}</span>\n    <span class=\"track-hint\">* 로컬 저장 (셀러랩스 순위추적 미연동)</span></button>`;\n\n  if(mode==='competition'||mode==='complete'){\n    html+=`<div class=\"gauge-box\"><h4 class=\"meta-h4\">📊 진입 난이도</h4>\n      <div class=\"gauge-head\"><span class=\"verdict\" style=\"color:${v.color}\">${v.label}</span>\n        <span class=\"gauge-score\">난이도 ${diff}/100</span></div>\n      <div class=\"gauge-track\"><div class=\"gauge-needle\" id=\"needle\" style=\"left:0%\"></div></div>\n      <div class=\"gauge-labels\"><span>쉬움</span><span>보통</span><span>어려움</span></div>\n      <div class=\"gauge-desc\">${v.desc}</div>\n      ${diff>=65?`<div class=\"opp-kw\"><span class=\"opp-label\">💡 기회 키워드 →</span>${db.oppKeywords.map(k=>`<span class=\"pill-green\">${esc(k)}</span>`).join('')}</div>`:''}\n    </div>`;\n  }\n\n  const barTitle=db.hasVolume?'📈 키워드별 검색량':'📈 상위 40개 등장 빈도';\n  const totalLine=db.hasVolume\n    ? `총 노출 검색량 <b>${total.toLocaleString()}회</b>`\n    : (db.totalProducts!=null?`네이버 쇼핑 전체 상품 <b>${db.totalProducts.toLocaleString()}개</b>`:'');\n  html+=`<div class=\"meta-grid\">\n    <div class=\"meta-box\"><h4 class=\"meta-h4\">${barTitle}</h4>\n      ${bars.map(b=>{const val=db.hasVolume?b.volume:b.freq;const unit=db.hasVolume?'회':'개 상품';\n        return `<div class=\"kw-bar\"><div class=\"kw-top\"><span>${esc(b.word)}</span><b>${val.toLocaleString()}${unit}</b></div>\n        <div class=\"kw-track\"><div class=\"kw-fill\" style=\"width:${val/maxV*100}%\"></div></div></div>`;}).join('')}\n      <div class=\"total-vol\">${totalLine}</div></div>\n    <div class=\"meta-box\"><h4 class=\"meta-h4\">🗂 추천 카테고리</h4><span class=\"pill\">${esc(db.category)}</span>\n      <h4 class=\"meta-h4\" style=\"margin-top:16px\">🏷 추천 태그</h4>\n      ${[...db.extraTags,...db.keywords.filter(k=>!used.includes(k.word)).map(k=>k.word)].slice(0,10).map(t=>`<span class=\"pill\">${esc(t)}</span>`).join('')}</div>\n  </div>`;\n\n  if(db.live&&db.sampleTitles&&db.sampleTitles.length){\n    html+=`<div class=\"reason\"><h4 class=\"meta-h4\">🔎 분석한 상위 상품명 (샘플)</h4><ol>\n      ${db.sampleTitles.map(t=>`<li>${esc(t)}</li>`).join('')}</ol></div>`;\n  }\n\n  if(mode!=='quick'){\n    const reasons=db.hasVolume\n      ? [`필수 키워드 \"${esc(kw)}\" 포함`,`상위노출 빈도 1위 키워드 우선 배치`,`검색량 최상위 키워드 결합으로 노출 확대`,\n         `동일 단어 비연속 배치로 SEO 패널티 회피`,`${used.length}개 단어 사용 (네이버 권장 7개 내외)`,`특수문자 0개 · 50자 이내 준수`]\n      : [`필수 키워드 \"${esc(kw)}\" 포함`,`네이버 쇼핑 상위 40개에서 가장 자주 쓰인 키워드 우선 배치`,\n         `상위 셀러들이 공통으로 쓰는 세부 키워드 결합`,`동일 단어 비연속 배치로 SEO 패널티 회피`,\n         `${used.length}개 단어 사용 (네이버 권장 7개 내외)`,`특수문자 0개 · 50자 이내 준수`];\n    html+=`<div class=\"reason\"><h4 class=\"meta-h4\">💡 왜 이 상품명일까요?</h4><ol>\n      ${reasons.map(r=>`<li>${r}</li>`).join('')}</ol></div>`;\n  }\n\n  const res=document.getElementById('result');\n  res.innerHTML=html;res.classList.add('show');\n\n  res.querySelectorAll('.copy-btn').forEach(btn=>btn.onclick=()=>{\n    navigator.clipboard.writeText(btn.dataset.copy);\n    const o=btn.textContent;btn.textContent='복사됨 ✓';setTimeout(()=>btn.textContent=o,1500);\n  });\n  const tBtn=document.getElementById('trackBtn');\n  tBtn.onclick=async()=>{\n    if(tBtn.disabled)return;\n    tBtn.disabled=true;document.getElementById('trackLabel').textContent='등록 중…';\n    await registerTracking({productName:name,mainKeyword:kw,category:db.category,totalVolume:total,difficulty:diff});\n    tBtn.classList.add('done');document.getElementById('trackLabel').textContent='✓ 등록 완료!';\n    setTimeout(()=>{document.getElementById('trackLabel').textContent='✓ 이미 추적 중';},1800);\n    renderTracked();\n  };\n\n  const needle=document.getElementById('needle');\n  if(needle)setTimeout(()=>needle.style.left=diff+'%',50);\n\n  renderTracked();\n  res.scrollIntoView({behavior:'smooth',block:'nearest'});\n}\n\nfunction renderTracked(){\n  const items=getTracked();const box=document.getElementById('trackedListBox');\n  if(!items.length){box.innerHTML=\"\";return;}\n  box.innerHTML=`<div class=\"tracked-panel\"><h4 class=\"meta-h4\">📋 내 추적 목록 (${items.length})</h4>\n    ${items.map(it=>{const volTxt=it.totalVolume>0?`검색량 ${it.totalVolume.toLocaleString()}회 · `:'';\n      return `<div class=\"tracked-row\">\n      <div><div class=\"tracked-name\">${esc(it.productName)}</div>\n        <div class=\"tracked-meta\">${volTxt}난이도 ${it.difficulty} · ${new Date(it.createdAt).toLocaleDateString('ko-KR')}</div></div>\n      <button class=\"tracked-del\" data-id=\"${it.id}\">삭제</button></div>`;}).join('')}</div>`;\n  box.querySelectorAll('.tracked-del').forEach(b=>b.onclick=()=>{removeTracking(b.dataset.id);renderTracked();\n    const tBtn=document.getElementById('trackBtn');if(tBtn){tBtn.disabled=false;tBtn.classList.remove('done');\n      const lbl=document.getElementById('trackLabel');if(lbl)lbl.textContent='📌 이 상품명으로 순위추적 등록하기';}});\n}\n\nfunction esc(s){return String(s).replace(/[&<>\"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',\"'\":'&#39;'}[c]));}\n\nrenderTracked();\ndetectMode().then(generate);\n</script>\n</body>\n</html>\n";
